import{_ as a,o,c as n,a3 as t}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"12. Seniors Allowance","description":"","frontmatter":{"title":"12. Seniors Allowance","eba":"Health Allied & Managers Admin 2021-2025","topics":["allowances","classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/allowances/12-seniors-allowance.md","filePath":"ebas/has-managers-admin/health-allied-services/allowances/12-seniors-allowance.md"}'),r={name:"ebas/has-managers-admin/health-allied-services/allowances/12-seniors-allowance.md"};function s(i,e,l,p,d,c){return o(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="_12-seniors-allowance" tabindex="-1">12. Seniors Allowance <a class="header-anchor" href="#_12-seniors-allowance" aria-label="Permalink to &quot;12. Seniors Allowance&quot;">​</a></h1><p>This clause does not apply to Dental Assistants employed by DHSV</p><p><strong>12.1</strong> An Employee who is appointed as a Senior will have their classification preceded by the word Senior and will be paid an allowance of 10 per cent of the base rate payable for their classification pursuant to <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>.</p><p><strong>12.2</strong> Appointment to a position preceded by the word Senior will only be made where the work performed by such Employee represents a net addition to the work value of the substantive role in a similar area or areas. Indicia of a new addition to work value may include:</p><p><strong>(a)</strong> the performance of additional duties or functions;</p><p><strong>(b)</strong> the assignment of a special project; or</p><p><strong>(c)</strong> an increased emphasis on the performance of core functions already undertaken by Employees in the relevant classification.</p><p><strong>12.3</strong> A net addition to the work value of the substantive role of an Employee would be characterised by the following:</p><p><strong>(a)</strong> the additional functions or duties are a regular and ongoing requirement; and</p><p><strong>(b)</strong> experience in the role commensurate with this clause, coupled with on the job training where provided by the Employer; and</p><p><strong>(c)</strong> the necessity for additional training in a particular aspect of the role above that which is required to fulfil the role of an Employee employed in a similar area(s); and</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>(d)</strong> a greater level of judgement is required from the Employee, whereby he or she is capable of making independent decisions to a degree not generally expected of an Employee employed in a similar area(s); and</p><p><strong>(e)</strong> a higher degree of accountability is expected for work undertaken, such that the Employee is clearly performing at a level above that of his or her peers employed in a similar area(s) by the Employer.</p><p><strong>12.4</strong> The Seniors Allowance will be additional to any other allowance to which the Employee is entitled under the Agreement.</p><p>Plain language terms: senior allowance, seniority.</p>',16)])])}const g=a(r,[["render",s]]);export{m as __pageData,g as default};
